#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

typedef struct Node {
    int val;
    struct Node *left, *right;
} Node;

Node* newNode(int v) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->val = v;
    n->left = n->right = NULL;
    return n;
}

void inorderDetect(Node* cur, Node** first, Node** second, Node** prev) {
    if (!cur) return;
    inorderDetect(cur->left, first, second, prev);
    if (*prev && (*prev)->val > cur->val) {
        if (!*first) *first = *prev;
        *second = cur;
    }
    *prev = cur;
    inorderDetect(cur->right, first, second, prev);
}

Node* recoverBST(Node* root) {
    Node *first = NULL, *second = NULL, *prev = NULL;
    inorderDetect(root, &first, &second, &prev);
    if (first && second) {
        int tmp = first->val;
        first->val = second->val;
        second->val = tmp;
    }
    return root;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        Node **nodes = (Node**)malloc((N+1) * sizeof(Node*));
        bool *isChild = (bool*)calloc(N+1, sizeof(bool));
        for (int i = 1; i <= N; ++i) nodes[i] = newNode(i);
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir; scanf("%d %d %c", &p, &c, &dir);
            if (dir == 'L') nodes[p]->left = nodes[c];
            else nodes[p]->right = nodes[c];
            isChild[c] = true;
        }
        int rootIdx = 1;
        for (int i = 1; i <= N; ++i) if (!isChild[i]) { rootIdx = i; break; }
        recoverBST(nodes[rootIdx]);
        printf("OK! BST recovered. Well done!\n");
        free(nodes);
        free(isChild);
    }
    return 0;
}

