public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { val = v; }
    }

    static void inorderDetect(Node cur, Node[] first, Node[] second, Node[] prev) {
        if (cur == null) return;
        inorderDetect(cur.left, first, second, prev);
        if (prev[0] != null && prev[0].val > cur.val) {
            if (first[0] == null) first[0] = prev[0];
            second[0] = cur;
        }
        prev[0] = cur;
        inorderDetect(cur.right, first, second, prev);
    }

    static Node recoverBST(Node root) {
        Node[] first = new Node[1];
        Node[] second = new Node[1];
        Node[] prev = new Node[1];
        inorderDetect(root, first, second, prev);
        if (first[0] != null && second[0] != null) {
            int tmp = first[0].val;
            first[0].val = second[0].val;
            second[0].val = tmp;
        }
        return root;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Node[] nodes = new Node[N+1];
