import sys

def inorder_detect(node, state):
    if not node:
        return
    inorder_detect(node.left, state)
    prev = state['prev']
    if prev and prev.val > node.val:
        if state['first'] is None:
            state['first'] = prev
        state['second'] = node
    state['prev'] = node
    inorder_detect(node.right, state)

def recover_bst(root):
    state = {'first': None, 'second': None, 'prev': None}
    inorder_detect(root, state)
    if state['first'] and state['second']:
        state['first'].val, state['second'].val = state['second'].val, state['first'].val
    return root

class Node:
    __slots__ = ('val', 'left', 'right')
    def __init__(self, v):
        self.val = v
        self.left = None
        self.right = None

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        nodes = [None] + [Node(i) for i in range(1, N+1)]
        is_child = [False]*(N+1)
        for _ in range(N-1):
            p, c, d = next(it).split()
            p = int(p); c = int(c)
            if d == 'L':
                nodes[p].left = nodes[c]
            else:
                nodes[p].right = nodes[c]
            is_child[c] = True
        root_idx = 1
        for i in range(1, N+1):
            if not is_child[i]:
                root_idx = i
                break
        recover_bst(nodes[root_idx])
        out_lines.append('OK! BST recovered. Well done!')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

